    56→// StartCSISyncLoop 启动CSI配置同步循环
    57→func StartCSISyncLoop(k8sClient k8s.Client) {
    58→	// 使用wait.Until启动定时同步循环
    59→	go wait.Until(func() {
    60→		// 获取StorageClass信息
    61→		sc, err := getStorageClassInfo(k8sClient, storageClassName)
    62→		if err != nil {
    63→			// 记录错误但继续运行
    64→			return
    65→		}
    66→		// 更新CSI配置
    67→		SetCSIConfig(sc)
    68→	}, 30*time.Second, wait.NeverStop)
    69→}
    70→
    71→// getStorageClassInfo 从k8s获取StorageClass信息并转换为CSIConfig
    72→func getStorageClassInfo(k8sClient k8s.Client, className string) (*CSIConfig, error) {
    73→	ctx := context.Background()
    74→	if k8sClient == nil {
    75→		return nil, fmt.Errorf("k8s client is nil")
    76→	}
    77→	sc, err := k8sClient.GetStorageClass(ctx, className)
    78→	if err != nil {
    79→		return nil, fmt.Errorf("failed to get storage class %s: %w", className, err)
    80→	}
    81→
    82→	config := &CSIConfig{
    83→		Driver:            sc.Provisioner,
    84→		ReclaimPolicy:     *sc.ReclaimPolicy,
    85→		VolumeBindingMode: *sc.VolumeBindingMode,
    86→		Parameters:        make(map[string]string),
    87→		MountOptions:      make([]string, len(sc.MountOptions)),
    88→	}
    89→
    90→	// 复制参数
    91→	for k, v := range sc.Parameters {
    92→		config.Parameters[k] = v
    93→	}
    94→
    95→	// 复制挂载选项
    96→	copy(config.MountOptions, sc.MountOptions)
    97→
    98→	// 从参数中提取 Secret 信息
    99→	if secretName, exists := config.Parameters["csi.storage.k8s.io/node-publish-secret-name"]; exists {
   100→		config.SecretName = secretName
   101→	}
   102→	if secretNamespace, exists := config.Parameters["csi.storage.k8s.io/node-publish-secret-namespace"]; exists {
   103→		config.SecretNamespace = secretNamespace
   104→	}
   105→	if juiceFSImage, exists := config.Parameters["juicefs/mount-image"]; exists {
   106→		config.JuiceFSImage = juiceFSImage
   107→	}
   108→
   109→	return config, nil
   110→}
   111→
   112→// SyncCSIConfigFromStorageClass 从StorageClass同步CSI配置
   113→func SyncCSIConfigFromStorageClass(k8sClient k8s.Client) error {
   114→	sc, err := getStorageClassInfo(k8sClient, storageClassName)
   115→	if err != nil {
   116→		return fmt.Errorf("failed to get storage class info: %w", err)
   117→	}
   118→	SetCSIConfig(sc)
   119→	return nil
   120→}
