   175→// buildSharedPVC 构建 namespace 级共享 PersistentVolumeClaim
   176→// 通过 spec.volumeName 显式绑定到集群共享 PV
   177→func buildSharedPVC(namespace, pvcName, pvName string, readOnly bool) *corev1.PersistentVolumeClaim {
   178→	accessMode := corev1.ReadWriteMany
   179→	if readOnly {
   180→		accessMode = corev1.ReadOnlyMany
   181→	}
   182→
   183→	storageClass := ""
   184→	return &corev1.PersistentVolumeClaim{
   185→		ObjectMeta: metav1.ObjectMeta{
   186→			Name:      pvcName,
   187→			Namespace: namespace,
   188→		},
   189→		Spec: corev1.PersistentVolumeClaimSpec{
   190→			VolumeName:       pvName,
   191→			AccessModes:      []corev1.PersistentVolumeAccessMode{accessMode},
   192→			StorageClassName: &storageClass,
   193→			Resources: corev1.VolumeResourceRequirements{
   194→				Requests: corev1.ResourceList{
   195→					corev1.ResourceStorage: resource.MustParse(defaultStorageSize),
   196→				},
   197→			},
   198→		},
   199→	}
   200→}
   201→
   202→// buildSharedVolumes 根据 storage 列表构建共享卷（去重，最多 2 个）
   203→// ReadOnly=false 的 storage 共用 shared-rw-volume
   204→// ReadOnly=true  的 storage 共用 shared-ro-volume
   205→func buildSharedVolumes(storages []devmachinemodel.Storage) []corev1.Volume {
   206→	if len(storages) == 0 {
   207→		return nil
   208→	}
   209→
   210→	volumes := make([]corev1.Volume, 0, 2)
   211→	hasRW, hasRO := false, false
   212→
   213→	for _, s := range storages {
   214→		if !s.ReadOnly && !hasRW {
   215→			hasRW = true
   216→			volumes = append(volumes, corev1.Volume{
   217→				Name: SharedRWVolumeName,
   218→				VolumeSource: corev1.VolumeSource{
   219→					PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
   220→						ClaimName: SharedRWPVCName,
   221→					},
   222→				},
   223→			})
   224→		}
   225→		if s.ReadOnly && !hasRO {
   226→			hasRO = true
   227→			volumes = append(volumes, corev1.Volume{
   228→				Name: SharedROVolumeName,
   229→				VolumeSource: corev1.VolumeSource{
   230→					PersistentVolumeClaim: &corev1.PersistentVolumeClaimVolumeSource{
   231→						ClaimName: SharedROPVCName,
   232→						ReadOnly:  true,
   233→					},
   234→				},
   235→			})
   236→		}
   237→	}
   238→
   239→	return volumes
   240→}
   241→
   242→// buildSharedVolumeMounts 构建共享卷挂载列表（每条 storage 独立挂载，subPath 隔离）
   243→func buildSharedVolumeMounts(storages []devmachinemodel.Storage) []corev1.VolumeMount {
   244→	if len(storages) == 0 {
   245→		return nil
   246→	}
   247→
   248→	mounts := make([]corev1.VolumeMount, 0, len(storages))
   249→	for _, s := range storages {
   250→		volName := SharedRWVolumeName
   251→		if s.ReadOnly {
   252→			volName = SharedROVolumeName
   253→		}
   254→		mounts = append(mounts, corev1.VolumeMount{
   255→			Name:      volName,
   256→			MountPath: s.MountPath,
   257→			SubPath:   s.StoragePath,
   258→			ReadOnly:  s.ReadOnly,
   259→		})
   260→	}
   261→
   262→	return mounts
   263→}
