   101→	if err := ValidateDevmachineForModify(request.Name, request.Namespace, request.ImageName); err != nil {
   102→		return nil, NewValidationError("devmachine", request.Name, err)
   103→	}
   104→
   105→	var err error
   106→
   107→	defer func() {
   108→		if err != nil {
   109→			log.Printf("error: failed to create devmachine, try to cleanup: %v", err)
   110→			_, _ = s.DeleteDevmachine(ctx, request.Namespace, request.Name)
   111→		}
   112→	}()
   113→
   114→	// 1. 兼容兜底：确保 namespace 下共享 PVC 存在（历史 namespace 补建）
